#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int V[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &V[i]);
        }
        double expectedValue = 0;
        for (int i = 0; i < N; i++) {
            expectedValue += (double)V[i] / 2;
        }
        printf("%.3f\n", expectedValue);
    }
    return 0;
}

