import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] V = new int[N];
            for (int i = 0; i < N; i++) {
                V[i] = sc.nextInt();
            }
            double expectedValue = 0;
            for (int i = 0; i < N; i++) {
                expectedValue += (double)V[i] / 2;
            }
            System.out.printf("%.3f\n", expectedValue);
        }
    }
}

